1	/**
2	 * A live cell on the Game of Life grid, represented as [x, y] coordinates.
3	 * The grid is conceptually infinite; only live cells are tracked.
4	 */
5	export type Cell = [number, number];
6	
7	/**
8	 * Computes the next generation of live cells from the current generation
9	 * by applying Conway's Game of Life rules:
10	 * - A live cell with 2 or 3 live neighbors survives.
11	 * - A dead cell with exactly 3 live neighbors becomes alive (reproduction).
12	 * - All other cells are dead in the next generation (underpopulation
13	 *   when <2 live neighbors, overpopulation when >3).
14	 */
15	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
16	  [-1, -1], [0, -1], [1, -1],
17	  [-1,  0],          [1,  0],
18	  [-1,  1], [0,  1], [1,  1],
19	];
20	
21	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
22	
23	export function nextGeneration(currentGeneration: Cell[]): Cell[] {
24	  const liveKeys = new Set(currentGeneration.map(cellKey));
25	  const neighbors = new Map<string, { cell: Cell; liveNeighborCount: number }>();
26	
27	  for (const [x, y] of currentGeneration) {
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const cell: Cell = [x + dx, y + dy];
30	      const key = cellKey(cell);
31	      const entry = neighbors.get(key);
32	      if (entry) entry.liveNeighborCount++;
33	      else neighbors.set(key, { cell, liveNeighborCount: 1 });
34	    }
35	  }
36	
37	  const survives = (key: string, liveNeighborCount: number): boolean =>
38	    liveNeighborCount === 3 || (liveNeighborCount === 2 && liveKeys.has(key));
39	
40	  const next: Cell[] = [];
41	  for (const [key, { cell, liveNeighborCount }] of neighbors) {
42	    if (survives(key, liveNeighborCount)) next.push(cell);
43	  }
44	  return next;
45	}
