1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent live cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: middle of a horizontal triple survives — (1,0) has 2 live neighbors", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("Rule 3 Overpopulation: center of 3x3 block dies — (1,1) has 8 live neighbors", () => {
19	    const fullBlock: [number, number][] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(fullBlock);
25	    expect(result).not.toContainEqual([1, 1]);
26	    expect(result).toContainEqual([0, 0]);
27	  });
28	  it("Rule 4 Reproduction: dead (1,1) with exactly 3 live neighbors becomes alive — [(0,0),(1,0),(0,1)] → contains (1,1)", () => {
29	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
30	    expect(result).toContainEqual([1, 1]);
31	  });
32	  it("Block still life is stable — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
33	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
34	    const result = nextGeneration(block);
35	    expect(result).toHaveLength(4);
36	    for (const cell of block) {
37	      expect(result).toContainEqual(cell);
38	    }
39	  });
40	  it("Blinker oscillates: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
41	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
42	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
43	    expect(result).toHaveLength(3);
44	    for (const cell of expected) {
45	      expect(result).toContainEqual(cell);
46	    }
47	  });
48	  it("handles negative coordinates (blinker at (-10,-10..-8)) — rotates to horizontal", () => {
49	    const result = nextGeneration([[-10, -10], [-10, -9], [-10, -8]]);
50	    const expected: [number, number][] = [[-11, -9], [-10, -9], [-9, -9]];
51	    expect(result).toHaveLength(3);
52	    for (const cell of expected) {
53	      expect(result).toContainEqual(cell);
54	    }
55	  });
56	});
